#include<bits/stdc++.h>
using namespace std;
long long n,m,p,len,a[200010],num[200010],cnt[200010],sum,ans[200010];
struct node
{
    long long l,r,id;
    bool operator<(const node&b)const
    {
        if(l/len!=b.l/len)
        {
            return l<b.l;
        }
        return (((l/len)&1)?r<b.r:r>b.r);
    }
}h[200010];
struct node1
{
    long long d,id;
    bool operator<(const node1&b)const
    {
        return d<b.d;
    }
}s[200010];
char str[200010];
void add(long long x)
{
    sum+=cnt[num[x]];
    cnt[num[x]]++;
}
void del(long long x)
{
    cnt[num[x]]--;
    sum-=cnt[num[x]];
}
int main()
{
    scanf("%lld%s",&p,str+1);
    n=strlen(str+1);
    for(int i=1;i<=n;i++)
    {
        a[i]=str[i]-'0';
    }
    if(10%p==0)
    {
        for(int i=1;i<=n;i++)
        {
            s[i]=s[i-1];
            if(a[i]%p==0)
            {
                s[i].d+=i;
                s[i].id++;
            }
        }
        scanf("%lld",&m);
        while(m--)
        {
            long long l,r;
            scanf("%lld%lld",&l,&r);
            printf("%lld\n",s[r].d-s[l-1].d-(l-1)*(s[r].id-s[l-1].id));
        }
        return 0;
    }
    len=sqrt(n);
    long long p1=1;
    for(int i=n;i>=1;i--)
    {
        s[i].d=(s[i+1].d+a[i]*p1)%p;
        s[i].id=i;
        p1=p1*10%p;
    }
    s[++n].d=0;
    s[n].id=n;
    sort(s+1,s+1+n);
    int tot=0;
    for(int i=1;i<=n;i++)
    {
        if(i==1||s[i].d!=s[i-1].d)
        {
            tot++;
        }
        num[s[i].id]=tot;
    }
    scanf("%lld",&m);
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld",&h[i].l,&h[i].r);
        h[i].r++;
        h[i].id=i;
    }
    sort(h+1,h+1+m);
    long long l=1,r=0;
    for(long long i=1;i<=m;i++)
    {
        while(l<h[i].l)
        {
            del(l++);
        }
        while(l>h[i].l)
        {
            add(--l);
        }
        while(r<h[i].r)
        {
            add(++r);
        }
        while(r>h[i].r)
        {
            del(r--);
        }
        ans[h[i].id]=sum;
    }
    for(long long i=1;i<=m;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
